import xml.etree.ElementTree as ET

def validate_xml(file_path):
    try:
        tree = ET.parse(file_path)
        root = tree.getroot()
        print("XML is valid.")
        return True
    except ET.ParseError as e:
        print(f"Invalid XML: {e}")
        return False

